{% /* https://try.jsonata.org/XDJvywd0c */
/* Compare the draft tags to the libraries */
/* Get the draft tags */
(
    [ 
        $tags.(libraryId),
        $tags.(tumorLibraryId)
    ] ~> $sort
)
=
/* Get the draft detail libraries */ 
(
    [
        $librariesList.(libraryId)
    ] ~> $sort 
) %}

Assign.tags:
{% /* https://try.jsonata.org/05K2l3beH */
/* List to merge together */
[
    /* Start with the draft tags */
    $tags,
    /* Merge the results list together */
    $merge($states.result)
] 
/* Then merge these initial tags with states.result  */
~> $merge
/* Remove any keys with values */
~> $sift(function($v, $k){$v != null}) %}

Choices.Condition:
{% /* Get readsets for tag */
( 
  $librariesList ~>
  $single(function($libraryIter){
    $libraryIter.libraryId = $tags.libraryId
  }) ~>
  $lookup("readsets")
) ? true : false %}

{% /* Get readsets for tag */
( 
  $librariesList ~>
  $single(function($libraryIter){
    $libraryIter.libraryId = $tags.tumorLibraryId
  }) ~>
  $lookup("readsets")
) ? true : false %}

Assign.inputs:
{% /* https://try.jsonata.org/ZAkTIin-h */
[
  /* Get the default input params */
  $states.result[2],
  /* add existing inputs after defaults inputs */
  $inputs,
  /* Combine the states results */
  {
      "sequenceData": $states.result[0],
      "tumorSequenceData": $states.result[1]
  },
  /* Add in the required sampleName and tumorSampleName */
  /* These must match the value of the library id */
  {
    "sampleName": $tags.libraryId,
    "tumorSampleName": $tags.tumorLibraryId ? $tags.tumorLibraryId : null
  }
]
/* Combine old and new */
~> $merge
/* Sift out inputs with null values */
~> $sift(function($v, $k){ $v != null }) %}

Choices.Condition:
{% /* https://try.jsonata.org/Un-e-H6Jw */
/* Get fastq list rows and tumor fastq list rows */
/* Select only the read uris from each object */
/* And then convert to a list */
$append(
    $inputs.sequenceData.fastqListRows.{
        "r1": $.read1FileUri,
        "r2": $.read2FileUri
    },
    $inputs.sequenceData.tumorFastqListRows.{
        "r1": $.read1FileUri,
        "r2": $.read2FileUri
    }
).*
/* Filter to those that endwith "ora" */
~> $map(function($v){
    $v ~> $contains(/.ora$/) ? 1 : 0
}) 
/* Use sum to count the number of true values 
/* Return true if so otherwise false */ 
~> $sum > 0 %}

