Entries.Detail:
{% $merge([
  $detail,
  {
    "id": null,
    "status": "${__draft_event_status__}",
    "timestamp": $states.context.State.EnteredTime,
    "libraries": $librariesList,
    "payload": (
      $merge([
        $payload,
        {
          "refId": null,
          "data": ( 
            {
              "inputs": ( $inputs ? $inputs : null ),
              "engineParameters": ( $engineParameters ? $engineParameters : null ),
              "tags": ( $tags ? $tags : null )
            }
            /* Remove null inputs like refId */
            ~> $sift(function($v, $k){$v != null})
          )
        }
      ])
      /* Remove null inputs like refId */
      ~> $sift(function($v, $k){$v != null})
    )
  }
])
/* Remove null inputs like id */
~> $sift(function($v, $k){$v != null}) %}
